type InferClient<T> = {
  [K in keyof T]: T[K] extends { resolve: (...args: any) => infer R }
    ? () => Promise<R>
    : T[K] extends object
      ? InferClient<T[K]>
      : never
}

const appRouter = {
  users: {
    list: { resolve: () => [{ id: 1, name: "Alice" }] },
    create: { resolve: () => ({ id: 2, name: "Bob" }) },
  },
}

type Client = InferClient<typeof appRouter>

